using UnityEngine;

/// <summary>
/// Identidade do player para o sistema de diálogo de NPCs (Etapa 2): define o
/// nome mostrado no balão quando uma DialogueLine tem Speaker = Player.
///
/// Opcional: se o player não tiver este componente, o balão usa "Jogador"
/// como nome por defeito.
/// </summary>
public class PlayerIdentity : MonoBehaviour
{
    [Tooltip("Nome mostrado no balão de diálogo quando o player fala. Se vazio, usa \"Jogador\".")]
    public string displayName = "Jogador";

    /// <summary>Nome a mostrar no balão. Se "displayName" estiver vazio, usa "Jogador".</summary>
    public string DisplayName => string.IsNullOrEmpty(displayName) ? "Jogador" : displayName;
}
